class NativeBridge(
    private val activity: ComponentActivity,
    private val webView: WebView,
    private val prefs: SharedPreferences,
    private val requestCameraPermission: ActivityResultLauncher<String>,
    private val requestNotificationsPermission: ActivityResultLauncher<String>,
    private val launchCameraCapture: (callbackJs: String) -> Unit,
    private val pushNotify: (title: String, body: String, channelId: String) -> Unit
) {

    @JavascriptInterface
    fun storageSet(key: String, value: String): Boolean {
        prefs.edit().putString(key, value).apply()
        return true
    }

    @JavascriptInterface
    fun storageGet(key: String, defaultValue: String?): String? {
        return prefs.getString(key, defaultValue)
    }

    @JavascriptInterface
    fun storageRemove(key: String): Boolean {
        prefs.edit().remove(key).apply()
        return true
    }

    @JavascriptInterface
    fun storageClear(): Boolean {
        prefs.edit().clear().apply()
        return true
    }

    @JavascriptInterface
    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= 33) {
            requestNotificationsPermission.launch(Manifest.permission.POST_NOTIFICATIONS)
        }
    }

    @JavascriptInterface
    fun showNotification(title: String, body: String, channelId: String?) {
        val ch = channelId?.takeIf { it.isNotBlank() } ?: "default"
        activity.runOnUiThread { pushNotify(title, body, ch) }
    }

    @JavascriptInterface
    fun openCamera(callbackFunctionName: String) {
        val cb = callbackFunctionName.trim()
        if (cb.isBlank()) return
        activity.runOnUiThread { launchCameraCapture(cb) }
    }

    @JavascriptInterface
    fun openExternalUrl(url: String) {
        val u = url.trim()
        if (u.isBlank()) return
        try {
            activity.startActivity(Intent(Intent.ACTION_VIEW, Uri.parse(u)))
        } catch (_: Throwable) {
        }
    }

    @JavascriptInterface
    fun postMessageToWeb(eventName: String, jsonPayload: String?) {
        val safeEvent = JSONObject.quote(eventName)
        val payload = jsonPayload ?: "null"
        activity.runOnUiThread {
            webView.evaluateJavascript(
                "(function(){var e=$safeEvent;var p=$payload;window.dispatchEvent(new CustomEvent(e,{detail:p}));})();",
                null
            )
        }
    }
}